#!/usr/bin/env bash
#
# Parses the Maven build log for apicurio-maven-plugin:verify-dependencies output
# and produces a markdown report of unaligned (non-redhat) dependencies.
#
# Usage: parse-unaligned-deps.sh <build-log> <output-md> [branch]

set -euo pipefail

BUILD_LOG="${1:?Usage: parse-unaligned-deps.sh <build-log> <output-md> [branch]}"
OUTPUT_MD="${2:?Usage: parse-unaligned-deps.sh <build-log> <output-md> [branch]}"
BRANCH="${3:-main}"
TODAY=$(date -u +%Y-%m-%d)

QUARKUS_PREFIXES="io.quarkus|io.smallrye|jakarta.|org.jboss|io.netty.netty-|org.hibernate|io.vertx"

UNALIGNED_JARS=$(grep -E '^\s+.*::.*\.jar$' "$BUILD_LOG" \
  | sed 's/.*:://' \
  | sed 's/\.jar$//' \
  | sort -u || true)

if [ -z "$UNALIGNED_JARS" ]; then
  cat > "$OUTPUT_MD" <<EOF
## Unaligned Dependencies Report
**Branch:** \`${BRANCH}\`
**Last checked:** ${TODAY}
**Total unaligned:** 0

All dependencies are productized. No action needed.

---
*Auto-generated by check-productization-deps workflow*
EOF
  echo "0"
  exit 0
fi

THIRD_PARTY=()
BOM_MANAGED=()

while IFS= read -r jar; do
  if echo "$jar" | grep -qE "^(${QUARKUS_PREFIXES})"; then
    BOM_MANAGED+=("$jar")
  else
    THIRD_PARTY+=("$jar")
  fi
done <<< "$UNALIGNED_JARS"

{
  cat <<EOF
## Unaligned Dependencies Report
**Branch:** \`${BRANCH}\`
**Last checked:** ${TODAY}
**Total unaligned:** $((${#THIRD_PARTY[@]} + ${#BOM_MANAGED[@]})) (${#THIRD_PARTY[@]} third-party, ${#BOM_MANAGED[@]} BOM-managed)

### Third-party dependencies (action needed)
These need PNC build configs in [pnc-config](https://gitlab.cee.redhat.com/apicurio/pnc-config):

| Artifact | Version |
|----------|---------|
EOF

  for jar in "${THIRD_PARTY[@]}"; do
    name=$(echo "$jar" | sed -E 's/-[0-9]+\..*//')
    version=$(echo "$jar" | sed -E "s/^${name}-//")
    echo "| \`${name}\` | \`${version}\` |"
  done

  cat <<EOF

### Managed by Quarkus BOM (informational)
These are expected to be covered by the Red Hat Quarkus build:

<details>
<summary>${#BOM_MANAGED[@]} dependencies</summary>

| Artifact | Version |
|----------|---------|
EOF

  for jar in "${BOM_MANAGED[@]}"; do
    name=$(echo "$jar" | sed -E 's/-[0-9]+\..*//')
    version=$(echo "$jar" | sed -E "s/^${name}-//")
    echo "| \`${name}\` | \`${version}\` |"
  done

  cat <<EOF

</details>

---
*Auto-generated by check-productization-deps workflow*
EOF
} > "$OUTPUT_MD"

echo "${#THIRD_PARTY[@]}"
